import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
import { createSudoku, createGame } from '../../../domain/index.js';

function emptyGrid() {
	return Array.from({ length: 9 }, () => Array(9).fill(0));
}

// grid store：持有"题目棋盘"（原始谜题），新游戏开始时由 game.js 调用 generate/decodeSencode 更新
function createGrid() {
	const grid = writable(emptyGrid());

	return {
		subscribe: grid.subscribe,

		generate(difficulty) {
			grid.set(generateSudoku(difficulty));
		},

		decodeSencode(sencode) {
			grid.set(decodeSencode(sencode));
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();

// ─── Store Adapter：gameStore ────────────────────────────────────────────────
//
// 这是本次作业的核心改动。
//
// 设计思路：
//   - 内部持有一个 Game 领域对象（game），它是游戏状态的"唯一权威来源"
//   - 对外暴露一个 Svelte 可订阅的 store，存的是 game 状态的"视图快照"
//   - 每次 game 发生变化（guess/undo/redo），调用 sync() 把 game 的最新状态
//     整体打包写入 writable → Svelte 检测到新值 → 界面自动刷新
//
// 为什么不直接 mutate game 然后让 Svelte 监听 game？
//   因为 Svelte 的响应式只认"赋值"：writable.set(新值) 才会通知订阅者刷新。
//   直接改 game.sudoku.cells[0][0] = 5 这样的字段赋值，Svelte 完全感知不到。
//   所以必须通过 set() 把"整个新状态"推给 store，Svelte 才会重新渲染。
//
function createGameStore() {
	// writable 里存的是"快照对象"，包含 UI 需要的全部数据
	const { subscribe, set } = writable({
		grid:         emptyGrid(), // 当前棋盘（cells，含玩家填写的数字）
		given:        emptyGrid(), // 题目固定格（非零 = 不可修改）
		canUndo:      false,
		canRedo:      false,
		invalidCells: [],          // 冲突格子坐标列表，由领域对象计算
	});

	let game = null;

	// 每当 grid store（题目）变化时（新游戏开始），重新创建 Game 领域对象
	grid.subscribe($grid => {
		const sudoku = createSudoku($grid);
		game = createGame({ sudoku });
		sync();
	});

	// sync：把 game 的最新状态打包成纯数据对象，写入 writable，触发 Svelte 刷新
	// 注意：这里没有两份数据——writable 存的只是 game 某时刻的快照，不是独立状态
	// invalidCells 也来自领域对象，校验逻辑内聚在 Sudoku.getInvalidCells()，不在 Store 层重复
	function sync() {
		set({
			grid:         game.getGrid(),
			given:        game.getGiven(),
			canUndo:      game.canUndo(),
			canRedo:      game.canRedo(),
			invalidCells: game.getInvalidCells(),
		});
	}

	return {
		subscribe,

		// 用户填写数字 → 调用领域对象 game.guess() → sync() 通知 Svelte 刷新
		guess(pos, value) {
			game.guess({ row: pos.y, col: pos.x, value });
			sync();
		},

		// 使用提示 → 求解当前棋盘 → 填入正确答案 → sync()
		applyHint(pos) {
			hints.useHint();
			const solvedSudoku = solveSudoku(game.getGrid());
			game.guess({ row: pos.y, col: pos.x, value: solvedSudoku[pos.y][pos.x] });
			sync();
		},

		// 撤销 → 领域对象恢复上一步快照 → sync()
		undo() {
			game.undo();
			sync();
		},

		// 重做 → 领域对象前进到下一步快照 → sync()
		redo() {
			game.redo();
			sync();
		},
	};
}

export const gameStore = createGameStore();

// invalidCells：校验逻辑已内聚在领域对象 Sudoku.getInvalidCells()，
// gameStore.sync() 每次更新时会将结果打包进快照。
// 此处只需从快照中透传，保持导出接口不变，所有消费方无需改动。
export const invalidCells = derived(gameStore, ($gameStore) => $gameStore.invalidCells ?? [], []);